package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Constructor;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Parameter;
import java.lang.reflect.Type;
import java.lang.reflect.Modifier;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  @Test
  void testConstructorToString_noParameters() throws Exception {
    class TestClassNoParams {
      public TestClassNoParams() {}
    }
    Constructor<TestClassNoParams> constructor = TestClassNoParams.class.getDeclaredConstructor();

    String result = ReflectionHelper.constructorToString(constructor);

    assertEquals("com.google.gson.internal.reflect.ReflectionHelperTest$1TestClassNoParams()", result);
  }

  @Test
  void testConstructorToString_withParameters() throws Exception {
    class TestClassWithParams {
      public TestClassWithParams(int a, String b) {}
    }
    Constructor<TestClassWithParams> constructor =
        TestClassWithParams.class.getDeclaredConstructor(int.class, String.class);

    String result = ReflectionHelper.constructorToString(constructor);

    assertEquals(
        "com.google.gson.internal.reflect.ReflectionHelperTest$2TestClassWithParams(int,java.lang.String)",
        result);
  }

  @Test
  void testConstructorToString_withArrayParameter() throws Exception {
    class TestClassArrayParam {
      public TestClassArrayParam(int[] arr) {}
    }
    Constructor<TestClassArrayParam> constructor =
        TestClassArrayParam.class.getDeclaredConstructor(int[].class);

    String result = ReflectionHelper.constructorToString(constructor);

    assertEquals(
        "com.google.gson.internal.reflect.ReflectionHelperTest$3TestClassArrayParam(int[])",
        result);
  }
}
